THOUGHT: Let me apply the fix more carefully by creating a patch file instead of using sed with complex escaping.

```bash
cat <<'EOF' > /tmp/looppeel_fix.patch
--- a/llvm/lib/Transforms/Utils/LoopPeel.cpp
+++ b/llvm/lib/Transforms/Utils/LoopPeel.cpp
@@ -854,7 +854,7 @@ static void cloneLoopBlocks(Loop *L, unsigned IterNumber, BasicBlock *PreHeader,
     for (PHINode &PHI : Edge.second->phis()) {
       Value *LatchVal = PHI.getIncomingValueForBlock(Edge.first);
       Instruction *LatchInst = dyn_cast<Instruction>(LatchVal);
-      if (LatchInst && L->contains(LatchInst))
+      if (LatchInst && L->contains(LatchInst) && !isa<PHINode>(LatchInst))
         LatchVal = VMap[LatchVal];
       PHI.addIncoming(LatchVal, cast<BasicBlock>(VMap[Edge.first]));
       SE.forgetLcssaPhiWithNewPredecessor(L, &PHI);
@@ -862,7 +862,8 @@ static void cloneLoopBlocks(Loop *L, unsigned IterNumber, BasicBlock *PreHeader,
   // LastValueMap is updated with the values for the current loop
   // which are used the next time this function is called.
   for (auto KV : VMap)
-    LVMap[KV.first] = KV.second;
+    if (!isa<PHINode>(KV.first))
+      LVMap[KV.first] = KV.second;
 }

 TargetTransformInfo::PeelingPreferences
EOF
```

```bash
cd /llvm-autofix-deps/llvm/llvm && patch -p1 < /tmp/looppeel_fix.patch
```

